Consider which of the following hold in
  \olref[aml][el][trw]{fig:simple}:
  \begin{enumerate}
    \item $\mSat{M}{\lnot q}[w_1]$;
    \item $\mSat{M}{\Knows_a \lnot q}[w_1]$;
    \item $\mSat{M}{\Knows_b \lnot q}[w_1]$;
    \item $\mSat{M}{\Knows_b q \lor \Knows_b \lnot q}[w_2]$;
    \item $\mSat{M}{\Knows_a( \Knows_b q \lor \Knows_b \lnot q)}[w_2]$;
    \item $\mSat{M}{\EKnows_{\{a,b\}} \lnot q}[w_3]$;
    \end{enumerate}

Show that there is a primitive recursive function~$\fn{tail}(s)$
with the property that
\begin{align*}
  \fn{tail}(\emptyseq) & = 0 \text{ and}\\
  \fn{tail}(\tuple{s_0, \dots, s_{k}}) & = \tuple{s_1, \dots, s_{k}}.
\end{align*}

Give \Log{S5}-counterexamples to the entailment relations which do not hold
  for the strict conditional, i.e., for:
  \begin{enumerate}
  \item $\lnot p \Entails/ \Box(p \lif q)$
  \item $q \Entails/ \Box(p \lif q)$
  \item $\lnot\Box(p \lif q) \Entails/ p \land \lnot q$
  \item $\Entails/ \Box(p \lif q) \lor \Box(q \lif p)$
  \end{enumerate}

Find !!{formula}s in $\Lang L_A$ which define the following relations:
\begin{enumerate}
\item $n$ is between $i$ and $j$;
\item $n$ evenly divides $m$ (i.e., $m$ is a multiple of $n$);
\item $n$ is a prime number (i.e., no number other than $1$ and $n$ evenly
  divides~$n$).
\end{enumerate}

Suppose the formula $!A(\Obj v_1, \Obj v_2)$ expresses the relation $R
\subseteq \Domain M^2$ in !!a{structure}~$\Struct M$.  Find formulas
that express the following relations:
\begin{enumerate}
\item the inverse $R^{-1}$ of $R$;
\item the relative product $R \mid R$;
\end{enumerate}
Can you find a way to express $R^+$, the transitive closure of~$R$?

Let $\Lang{L}$ be the language containing a 2-place predicate symbol
$<$ only (no other !!{constant}s, !!{function}s or !!{predicate}s---
except of course~$\eq$). Let $\Struct{N}$ be the structure such that
$\Domain{N} = \Nat$, and $\Assign{<}{N} = \Setabs{\tuple{n,m}}{n <
  m}$. Prove the following:
\begin{enumerate}
\item $\{ 0 \}$ is definable in $\Struct{N}$;
\item $\{ 1 \}$ is definable in $\Struct{N}$;
\item $\{ 2 \}$ is definable in $\Struct{N}$;
\item for each $n \in \Nat$, the set $\{ n \}$ is definable in
  $\Struct{N}$;
\item every finite subset of $\Domain{N}$ is definable in
  $\Struct{N}$;
\item every co-finite subset of $\Domain{N}$ is definable in
  $\Struct{N}$ (where $X \subseteq \Nat$ is co-finite iff
  $\Nat \setminus X$ is finite).
\end{enumerate}

Give closed !!{tableau}s of the following:
\begin{enumerate}
\item $\sFmla{\False}{\lnot\lforall[x][!A(x)] \lif \lexists[x][\lnot!A(x)]}$.
\item $\sFmla{\True}{(\lforall[x][!A(x)] \lif !B)}, \sFmla{\False}{\lexists[y][(!A(y) \lif !B)]}$.
\item $\sFmla{\False}{\lexists[x][(!A(x) \lif \lforall[y][!A(y)])]}$.
\end{enumerate}

Prove \olref[inc][art][frm]{prop:freeocc-primrec}.  You may make use
of the fact that any substring of !!a{formula} which is !!a{formula}
is a sub-!!{formula} of it.

!!^a{formula}~$!A(x)$ is a \emph{truth definition} if $\Th{Q}
  \Proves !B \liff !A(\gn{!B})$ for all !!{sentence}s~$!B$. Show that
  no !!{formula} is a truth definition by using the fixed-point lemma.

The term 
  \begin{align*}
    \fn{Succ}' & \ident \lambd[{n}][\lambd[fx][{n} f (f x)]]
  \end{align*}
  !!{lambda define}s the successor function. Explain why.

Are the following pairs of terms $\alpha$-convertible?
  \begin{enumerate}
  \item $\lambd[x][\lambd[y][x]]$ and $\lambd[y][\lambd[x][y]]$
  \item $\lambd[x][\lambd[y][x]]$ and $\lambd[c][\lambd[b][a]]$
  \item $\lambd[x][\lambd[y][x]]$ and $\lambd[c][\lambd[b][a]]$
  \end{enumerate}

\ollabel{prob:def}
  Spell out the equivalent inductive definitions of $\beta$-contraction as we
  did for change of bound variable in \olref[lam][syn][alp]{defn:aconvone}.

What is the result of the following substitutions?
  \begin{enumerate}
  \item $\Subst{\lambd[y][x(\lambd[w][vwx])]}{(uv)}{x}$
  \item $\Subst{\lambd[y][x(\lambd[x][x])]}{(\lambd[y][xy])}{x}$
  \item $\Subst{y(\lambd[v][xv])}{(\lambd[y][vy])}{x}$
  \end{enumerate}

Show that the following classical tautologies are not tautologies in~\LogLuk[3]:
  \begin{enumerate}
    \item $(\lnot p \land p) \lif q)$
    \item $((p \lif q) \lif p) \lif p$
    \item $(p \lif (p \lif q)) \lif (p \lif q)$
  \end{enumerate}

Prove that $\Struct{K}$ from \olref[mod][mar][mdq]{ex:model-K-of-Q}
satisfies the remaining axioms of~$\Th{Q}$,
\begin{align*}
  & \lforall[x][\eq[(x \times \Obj 0)][\Obj 0]] \tag{$!Q_6$}\\
  & \lforall[x][\lforall[y][\eq[(x \times y')][((x \times y) + x)]]] \tag{$!Q_7$}\\
  & \lforall[x][\lforall[y][(x < y \liff \lexists[z][\eq[(z' + x)][y]])]] \tag{$!Q_8$}
\end{align*}
Find !!a{sentence} only involving~$\prime$ true in~$\Struct{N}$ but
false in~$\Struct{K}$.

Expand $\Struct{L}$ of \olref[mod][mar][mdq]{ex:model-L-of-Q} to
include $\nstimes$ and $\nsless$ that interpret~$\times$ and $<$. Show
that your structure satisfies the remaining axioms of~$\Th{Q}$,
\begin{align*}
& \lforall[x][\eq[(x \times \Obj 0)][\Obj 0]] \tag{$!Q_6$}\\ &
  \lforall[x][\lforall[y][\eq[(x \times y')][((x \times y) + x)]]]
  \tag{$!Q_7$}\\ & \lforall[x][\lforall[y][(x < y \liff \lexists[z][\eq[(z'+x)][y]])]] \tag{$!Q_8$}
\end{align*}

Recall that $\Th{Q}$ contains the axioms
\begin{align*}
& \lforall[x][\lforall[y][(\eq[x'][y'] \lif \eq[x][y])]] \tag{$!Q_1$}\\
& \lforall[x][\eq/[\Obj 0][x']] \tag{$!Q_2$}\\
& \lforall[x][(\eq[x][\Obj 0] \lor \lexists[y][\eq[x][y']])] \tag{$!Q_3$}
\end{align*}
Give !!{structure}s~$\Struct{M_1}$, $\Struct{M_2}$, $\Struct{M_3}$ such that
\begin{enumerate}
\item $\Sat{M_1}{!Q_1}$, $\Sat{M_1}{!Q_2}$, $\Sat/{M_1}{!Q_3}$;
\item $\Sat{M_2}{!Q_1}$, $\Sat/{M_2}{!Q_2}$, $\Sat{M_2}{!Q_3}$; and
\item $\Sat/{M_3}{!Q_1}$, $\Sat{M_3}{!Q_2}$, $\Sat{M_3}{!Q_3}$;
\end{enumerate}
Obviously, you just have to specify~$\Assign{\Obj{0}}{M_i}$ and
$\Assign{\prime}{M_i}$ for each.

Show that the following !!{derivability} claims hold:
  \begin{enumerate}
  \item $\Log{K} \Proves \Diamond \lnot \lfalse \lif (\Box !A \lif
    \Diamond !A)$;
  \item $\Log{K} \Proves \Box(!A \lor !B) \lif (\Diamond !A \lor \Box
    !B)$;
  \item $\Log{K} \Proves (\Diamond !A \lif \Box !B) \lif \Box(!A \lif
    !B)$.
  \end{enumerate}

Find !!{derivation}s in~$\Log{K}$ for the following !!{formula}s:
  \begin{enumerate}
    \item $\Box \lnot p \lif \Box(p \lif q)$
    \item $(\Box p \lor \Box q) \lif \Box(p \lor q)$
    \item $\Diamond p \lif \Diamond(p \lor q)$
  \end{enumerate}

