      \draw[dotted] (000) to (0000);
      \draw[dotted] (000) to (0001);
      \draw[->] (00) to (001);
      \draw[dotted] (001) to (0010);
      \draw[dotted] (001) to (0011);
      \draw[->] (01) to (010);
