  We have $\mSat/{M}{\Box(p \lor q) \lif (\Box p \lor \Box q)}[w]$ for
  every~$w$.

  Let $\Gamma$ be the set of sub-!!{formula}s of~$\Box(p \lor q) \lif
  (\Box p \lor \Box q)$. What are $W^*$ and~$V^*$?  What is the
  accessibility relation of the finest filtration of~$\mModel{M}$? Of the
  coarsest?

Give sequent !!{derivation}s that show the following:
  \begin{enumerate}
  \item $\Log{KT5} \Proves \Ax{B}$;
  \item $\Log{KT5} \Proves \Ax{4}$;
  \item $\Log{KDB4} \Proves \Ax{T}$;
  \item $\Log{KB4} \Proves \Ax{5}$;
  \item $\Log{KB5} \Proves \Ax{4}$;
  \item $\Log{KT} \Proves \Ax{D}$.
  \end{enumerate}

Show that the following are valid:
  \begin{enumerate}
  \item $\Box p \lif \Box (q \lif p)$;
  \item $\Box \lnot \lfalse$;
  \item $\Box p \lif (\Box q \lif \Box p)$.
  \end{enumerate}

Show that none of the following !!{formula}s are valid:
  \begin{enumerate}
    \item[\Ax{D}:] \quad $\Box p \lif \Diamond p$;
    \item[\Ax{T}:] \quad $\Box p \lif p$;
    \item[\Ax{B}:] \quad $p \lif \Box\Diamond p$;
    \item[\Ax{4}:] \quad $\Box p \lif \Box \Box p$;
    \item[\Ax{5}:] \quad $\Diamond p \lif \Box \Diamond
      p$.
  \end{enumerate}

Decide whether the following schemas are valid or invalid:
  \begin{enumerate}
  \item $(\Diamond !A \lif \Box !B) \lif (\Box !A \lif \Box
    !B)$;
  \item $\Diamond(!A \lif !B) \lor \Box(!B \lif !A)$.
  \end{enumerate}

For each of the following schemas find a model $\mModel{M}$ such
  that every instance of the !!{formula} is true in $\mModel{M}$:
  \begin{enumerate}
  \item $p \lif \Diamond\Diamond p$;
  \item $\Diamond p \lif \Box p$.
  \end{enumerate}

Consider the model of \olref[nml][syn][rel]{fig:simple}. Which of the
  following hold?
    \begin{enumerate}
    \item $\mSat{M}{q}[w_1]$;
    \item $\mSat{M}{\lnot q}[w_3]$;
    \item $\mSat{M}{p \lor q}[w_1]$;
    \item $\mSat{M}{\Box (p \lor q)}[w_1]$;
    \item $\mSat{M}{\Box q}[w_3]$;
    \item $\mSat{M}{\Box \bot}[w_3]$;
    \item $\mSat{M}{\Diamond q}[w_1]$;
    \item $\mSat{M}{\Box q}[w_1]$;
    \item $\mSat{M}{\lnot \Box\Box \lnot q}[w_1]$.
    \end{enumerate}

Consider the following model $\mModel{M}$ for the language
  comprising $p_1$, $p_2$, $p_3$ as the only !!{propositional variable}s:
  \begin{center}
    \begin{tikzpicture}[modal]
      \node[world] (w1) [label={[align=right]left:\mTrue{p_1}\\\mFalse{p_2}\\\mFalse{p_3}}]
            {$w_1$} ; 
      \node[world] (w2) [label={[align=right]right:\mTrue{p_1}\\\mTrue{p_2}\\\mFalse{p_3}},
        below right=of w1]  {$w_2$}; 
      \node[world] (w3) [label={[align=right]right:\mTrue{p_1}\\\mTrue{p_2}\\\mTrue{p_3}},
        above right=of w2] {$w_3$};
      \draw[reflexive above] (w3) to (w3); 
      \draw[->] (w1) to (w2);
      \draw[->] (w2) to (w3);
      \draw[->] (w1) to (w3); 
    \end{tikzpicture}
  \end{center}
  Are the following !!{formula}s and schemas true in the model $\mModel{M}$,
  i.e., true at every world in $\mModel{M}$? Explain.
  \begin{enumerate}
  \item $p\lif \Diamond p$ (for $p$ atomic);
  \item $!A\lif \Diamond !A$ (for $!A$ arbitrary);
  \item $\Box p \lif p$ (for $p$ atomic);
  \item $\lnot p \lif \Diamond \Box p$ (for $p$ atomic);
  \item $\Diamond \Box !A$ (for $!A$ arbitrary);
  \item $\Box \Diamond p$ (for $p$ atomic). 
  \end{enumerate}

Give closed !!{tableau}s that show the following:
  \begin{enumerate}
  \item $\Log{KT5} \Proves \Ax{B}$;
  \item $\Log{KT5} \Proves \Ax{4}$;
  \item $\Log{KDB4} \Proves \Ax{T}$;
  \item $\Log{KB4} \Proves \Ax{5}$;
  \item $\Log{KB5} \Proves \Ax{4}$;
  \item $\Log{KT} \Proves \Ax{D}$.
  \end{enumerate}

Verify the sub-case of case~D in the proof of \olref{lem:cut-adm-G3c}
where $!A$ is not principal in the last inference of~$\pi_1$, which
ends in~$\LeftR{\lforall}$.

Verify the sub-case of case~E in the proof of \olref{lem:cut-adm-G3c}
where $!A$ is principal in the last inferences of both $\pi_1$ and
$\pi_2$ and $!A \ident (!B \land !C)$.

Verify the sub-case of case~E in the proof of \olref{lem:cut-adm-G3c}
where $!A$ is principal in the last inferences of both $\pi_1$ and
$\pi_2$ and $!A \ident \lexists[x][!B(x)]$.

Sketch the proof of \olref{prop:G3c-cont-adm} for \LeftR{\Contraction}
for the remaining quantifier cases, i.e., where $!A \ident
\lforall[x][!B(x)]$ and $!A \ident \lexists[x][!B(x)]$.

Consider adding to $\Lang{L_0}$ a ternary connective $\diamondsuit$
with evaluation given by
\begin{gather*}
  \pValue{v}(\diamondsuit( !A , !B , !C ) ) = \begin{cases}
    \pValue{v}( !B ) &
    \text{if $\pValue{v}(!A) = \True$;}\\
    \pValue{v}( !C ) &
    \text{if $\pValue{v}(!A) = \False $}.
  \end{cases}
\end{gather*}
Write down the truth table for this connective.

\label{sfr:siz:red:prob:nat-nat}
  Show that the set~$X$ of all functions $f\colon \Nat \to \Nat$ is
  !!{nonenumerable} by a reduction argument (Hint: give a surjective
  function from $X$ to~$\Bin^\omega$.)

\label{sfr:siz:red:prob:nat-nat}
  Show that the set~$X$ of all functions $f\colon \Nat \to \Nat$ is
  !!{nonenumerable} by a reduction argument (Hint: give a surjective
  function from $X$ to~$\Bin^\omega$.)

\label{tur:mac:dis:prob:copier}
Find a disciplined machine which, when started on input $\TMstroke^n$
produces output $\TMstroke^n \concat \TMblank \concat \TMstroke^n$.

\emph{Equality:} Design a Turing machine to compute the following function:
\[
\fn{equality}(n,m) = 
\begin{cases}
  \text{1} & \text{if~$n = m$} \\
  \text{0} & \text{if~$n \neq m$}
\end{cases}
\]
where~$n$ and~$m \in \PosInt$.

Show that the \emph{partial} function~$s'$ is defined as
  \[
  s'(e) =
  \begin{cases}
    \text{1} & \text{if machine~$M_e$ halts for input $e$}\\
    \text{undefined} & \text{if machine~$M_e$ does not halt for input $e$}
  \end{cases}
  \]
  \emph{is} Turing computable.
